import{_ as t,o as a,c as r,a2 as i}from"./chunks/framework.c3r8iWL8.js";const h=JSON.parse('{"title":"SOP-001: Feature Intake & Prioritization","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"sops/SOP-001-feature-intake.md","filePath":"sops/SOP-001-feature-intake.md","lastUpdated":1782929962000}'),o={name:"sops/SOP-001-feature-intake.md"};function s(n,e,l,d,c,p){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="sop-001-feature-intake-prioritization" tabindex="-1">SOP-001: Feature Intake &amp; Prioritization <a class="header-anchor" href="#sop-001-feature-intake-prioritization" aria-label="Permalink to &quot;SOP-001: Feature Intake &amp; Prioritization&quot;">​</a></h1><p><strong>Version:</strong> 1.0 · <strong>Owner:</strong> Product Owner · <strong>Gate:</strong> G0</p><h2 id="purpose-scope" tabindex="-1">Purpose &amp; scope <a class="header-anchor" href="#purpose-scope" aria-label="Permalink to &quot;Purpose &amp; scope&quot;">​</a></h2><p>Convert raw business requests into scored, tier-classified backlog items ready for spec/ADR work (SOP-002, SOP-003).</p><p><strong>In scope:</strong> Epics, features, architectural spikes. <strong>Out of scope:</strong> Production bug fixes (use SOP-007/008 track).</p><h2 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>RACI</th></tr></thead><tbody><tr><td>PO</td><td><strong>A/R</strong> — triage, prioritize</td></tr><tr><td>ARCH</td><td>C — feasibility, tier validation</td></tr><tr><td>DEV</td><td>C — estimate complexity</td></tr><tr><td>SEC</td><td>C — data classification when PII involved</td></tr></tbody></table><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Request logged in backlog tool (Jira/Linear) with requester and business context</li><li>Access to existing service catalog (Backstage)</li></ul><h2 id="procedure" tabindex="-1">Procedure <a class="header-anchor" href="#procedure" aria-label="Permalink to &quot;Procedure&quot;">​</a></h2><ol><li><strong>Log request</strong> — Create ticket with: problem statement, success metric, target date, affected users.</li><li><strong>Classify data</strong> — SEC consult if PII, payments, or regulated data (≤ 1 day).</li><li><strong>Assign service tier</strong> — ARCH confirms T1/T2/T3 per <a href="./../GOVERNANCE.html">GOVERNANCE.md</a>.</li><li><strong>AI-assisted sizing</strong> — Planning agent produces: similar past work, draft acceptance criteria, dependency list. PO validates.</li><li><strong>Score &amp; prioritize</strong> — PO ranks using RICE or WSJF; documents decision in ticket.</li><li><strong>Route</strong> — If architectural fork likely → flag <code>needs-adr</code>. If API change → flag <code>needs-spec</code>.</li><li><strong>Schedule</strong> — Place in refinement queue; link to epic.</li></ol><h2 id="definition-of-done" tabindex="-1">Definition of Done <a class="header-anchor" href="#definition-of-done" aria-label="Permalink to &quot;Definition of Done&quot;">​</a></h2><ul><li>[ ] Ticket has tier, priority score, acceptance criteria draft</li><li>[ ] Data classification recorded</li><li>[ ] Flags set: <code>needs-adr</code> / <code>needs-spec</code> / neither</li><li>[ ] PO comment: approved for define phase</li></ul><h2 id="sla-escalation" tabindex="-1">SLA &amp; escalation <a class="header-anchor" href="#sla-escalation" aria-label="Permalink to &quot;SLA &amp; escalation&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Milestone</th><th>SLA</th></tr></thead><tbody><tr><td>Triage</td><td>2 business days from submission</td></tr><tr><td>SEC classification (when required)</td><td>1 business day</td></tr></tbody></table><p>Escalation: blocked &gt; SLA → EM.</p><h2 id="related-sops" tabindex="-1">Related SOPs <a class="header-anchor" href="#related-sops" aria-label="Permalink to &quot;Related SOPs&quot;">​</a></h2><ul><li><a href="./SOP-002-adr-lifecycle.html">SOP-002</a> · <a href="./SOP-003-spec-approval.html">SOP-003</a> · <a href="./SOP-012-exception-handling.html">SOP-012</a></li></ul>',18)])])}const f=t(o,[["render",s]]);export{h as __pageData,f as default};
